output.message:
{
  "steps": [
    {
      "step_id": "cb_step_1",
      "title": "Select Pelvic CT Volume",
      "simple": "Choose the Pelvic Volume from the Input CT Volume dropdown.",
      "detailed": "This step identifies the CT scan of your patient's pelvis, which is the starting point for all subsequent analysis. Selecting the correct volume ensures that pelvic bone segmentation and fracture assessment are performed on the correct imaging data. Find and select the pelvic CT volume from the dropdown list."
    },
    {
      "step_id": "cb_step_2",
      "title": "Segment Pelvis",
      "simple": "Click the 'Run Step 1: Segment Pelvis' button.",
      "detailed": "This step automatically outlines the pelvic bone from the CT scan, creating a segmentation that separates the pelvis from surrounding tissues. The resulting pelvic mask is the foundation for identifying fracture fragments and planning surgical reduction. Press the button and wait for the segmentation to complete."
    },
    {
      "step_id": "cb_step_3",
      "title": "Segment Fractures",
      "simple": "Click the 'Run Step 2: Segment Fractures' button.",
      "detailed": "This step identifies and separates individual fracture fragments within the pelvic bone segmentation. Accurate fragment segmentation is critical for planning reduction and visualizing the displacement pattern. Press the button and wait for the algorithm to complete."
    },
    {
      "step_id": "cb_step_4",
      "title": "Exclude Unwanted Fragments",
      "simple": "Untick any fragments you wish to exclude from the surgical plan.",
      "detailed": "You may choose to exclude small, non-displaced, or clinically irrelevant fragments from the planning process. This simplifies the plan and focuses attention on the fragments that require reduction. Review the list of segmented fragments and uncheck those that should not be included in subsequent steps."
    },
    {
      "step_id": "cb_step_5",
      "title": "Generate Reduction Template",
      "simple": "Click the 'Run Step 3: Generate Template' button.",
      "detailed": "This step creates an anatomical template — a model of the intact or reduced pelvis — that serves as the target for fracture reduction. The template is derived from the included fragments and helps guide alignment. Press the button to generate the template."
    },
    {
      "step_id": "cb_step_6",
      "title": "Run Reduction Registration",
      "simple": "Click the 'Run Step 4: Register Reduce' button.",
      "detailed": "This step automatically registers and reduces the fracture fragments to the anatomical template, computing the optimal positions for restoring pelvic anatomy. The result is a virtual reduction showing how the fragments should be aligned. Press the button and wait for the registration to complete."
    },
    {
      "step_id": "cb_step_7",
      "title": "Decide on Manual Fragment Adjustment",
      "simple": "If further adjustments are needed, tick the 'Manually adjust a fragment' checkbox.",
      "detailed": "After automatic reduction, you may need to fine-tune the position or rotation of individual fragments to achieve better anatomical alignment. If the reduction looks satisfactory, skip this step by leaving the box unchecked and proceed to step 11. If adjustments are needed, check the box to proceed."
    },
    {
      "step_id": "cb_step_8",
      "title": "Select Fragment to Adjust",
      "simple": "Choose which fragment needs adjustment from the Fragment selection box.",
      "detailed": "Select the specific fracture fragment you want to manually reposition or rotate. This allows you to work on one fragment at a time for precise control. Pick the fragment from the dropdown list."
    },
    {
      "step_id": "cb_step_9",
      "title": "Adjust Fragment Position and Rotation",
      "simple": "Use the transform controls to adjust the selected fragment's position and rotation.",
      "detailed": "In the 3D view, use the interactive transform widget (move/rotate handles) to align the fragment to your desired position. This manual adjustment is useful for correcting residual displacement not handled by the automatic reduction. When satisfied, click Done to confirm."
    },
    {
      "step_id": "cb_step_10",
      "title": "Apply Fragment Adjustments",
      "simple": "Click the 'Apply adjustments' button to save your changes.",
      "detailed": "This step commits the manual position and rotation changes you made to the fragment. The adjusted fragment will be used in subsequent planning steps. Click the button to apply."
    },
    {
      "step_id": "cb_step_11",
      "title": "Plan Screw Trajectories",
      "simple": "Click the 'Run Step 5: Plan Screws' button.",
      "detailed": "This step automatically computes optimal screw trajectories for fixation based on the reduced pelvic model. The screw plans ensure safe and effective placement of fixation hardware. Press the button to generate the screw trajectories."
    },
    {
      "step_id": "cb_step_12",
      "title": "Decide on Screw Trajectory Editing",
      "simple": "If further adjustments are needed, tick the 'Edit Screw trajectories' checkbox.",
      "detailed": "If the automatically planned screw trajectories need modification (e.g., to avoid a joint surface or improve bone purchase), choose Yes. If the trajectories are satisfactory, choose No to finish the workflow. This step allows you to fine-tune screw placement."
    },
    {
      "step_id": "cb_step_13",
      "title": "Adjust Screw Trajectories",
      "simple": "Use the transform controls to adjust the position and rotation of the screw trajectories.",
      "detailed": "In the 3D view, manipulate the screw trajectory lines or points to redirect the screws as needed. Adjustments may be required to optimize fixation strength or avoid critical structures. When finished, click Done."
    },
    {
      "step_id": "cb_step_14",
      "title": "Regenerate Screws from Edited Lines",
      "simple": "Click the 'Regenerate screws from edited lines' button.",
      "detailed": "This step recalculates the screw parameters (length, diameter, position) based on the manually edited trajectories. The updated screw models will reflect your changes. Press the button to regenerate."
    },
    {
      "step_id": "cb_step_15",
      "title": "Disable Screw Trajectory Editing",
      "simple": "Untick the 'Edit Screw trajectories' checkbox to exit editing mode.",
      "detailed": "This step finalizes the screw planning and returns the interface to the main workflow view. The screw trajectories are now finalized for the surgical plan. Uncheck the box to proceed."
    }
  ]
}
